import json
import jsonschema
from openai import OpenAI

client = OpenAI()

def call_with_schema_retry(messages, schema, max_retries=3):
    for attempt in range(1, max_retries + 1):
        response = client.chat.completions.create(
            model="gpt-4o",
            messages=messages,
            response_format={"type": "json_object"},
        )
        raw = response.choices[0].message.content
        try:
            data = json.loads(raw)
        except json.JSONDecodeError as e:
            messages = messages + [
                {"role": "assistant", "content": raw},
                {"role": "user", "content": f"Invalid JSON: {e}. Retry with valid JSON."},
            ]
            continue
        try:
            jsonschema.validate(data, schema)
            return data  # success
        except jsonschema.ValidationError as e:
            if attempt == max_retries:
                raise RuntimeError(
                    f"Schema validation failed after {max_retries} attempts: {e.message}"
                ) from e
            messages = messages + [
                {"role": "assistant", "content": raw},
                {"role": "user", "content": (
                    f"Your response did not match the required schema.\n"
                    f"Error at {e.json_path}: {e.message}\n"
                    "Please correct and respond with valid JSON only."
                )},
            ]
    raise RuntimeError("Max retries exhausted")

import json
import jsonschema

TOOL_SCHEMA = {
    "type": "object",
    "required": ["tool", "args"],
    "additionalProperties": False,
    "properties": {
        "tool": {
            "type": "string",
            "enum": ["search_web", "read_file", "python_exec", "done"]
        },
        "args": {"type": "object"},
        "reasoning": {"type": "string", "maxLength": 300},
    },
}

def validate_action(response_text: str) -> dict:
    """Parse and validate a tool-dispatch JSON string."""
    try:
        data = json.loads(response_text)
    except json.JSONDecodeError as exc:
        raise ValueError(f"Response is not valid JSON: {exc}") from exc

    errors = list(jsonschema.Draft202012Validator(TOOL_SCHEMA).iter_errors(data))
    if errors:
        messages = [f"  - {e.json_path}: {e.message}" for e in errors]
        raise ValueError("Schema violations:\n" + "\n".join(messages))

    return data


# --- demo ---
valid_output = '{"tool": "search_web", "args": {"query": "JSON Schema tutorial"}}'
result = validate_action(valid_output)
print("Valid:", result)

invalid_output = '{"tool": "fly_to_moon", "reasoning": 42}'
try:
    validate_action(invalid_output)
